        if (ironDeficit && b12Deficit && folateDeficit) anemiaRisk = 100;

        const score = Math.max(0, Math.min(100, Math.round(energyBscore * 0.4 + bloodBscore * 0.3 + (100 - anemiaRisk) * 0.3)));
